63	/** Compute the time bounds of all audible clips in the session */
64	export function computeSessionBounds(
65	  tracks: readonly TrackModel[],
66	  clips: Readonly<Record<string, ClipModel>>,
67	): SessionBounds {
68	  const audible = getAudibleTrackIds(tracks);
69	  let start = Infinity;
70	  let end = 0;
71	
72	  for (const track of tracks) {
73	    if (!audible.has(track.id)) continue;
74	    for (const clipId of track.clipIds) {
75	      const clip = clips[clipId];
76	      if (!clip) continue;
77	      start = Math.min(start, clip.startTime);
78	      end = Math.max(end, clip.startTime + clip.duration);
79	    }
80	  }
81	
82	  if (start === Infinity) start = 0;
83	  return { start, end };
84	}
