```typescript
export type ChannelStrip = {
  readonly trackId: string;
  readonly inputGain: GainNode;
  readonly inserts: readonly InsertSlot[];
  readonly preFaderTap: GainNode; // Pre-fader send point
  readonly faderGain: GainNode;
  readonly panner: StereoPannerNode;
  readonly muteGain: GainNode; // Mute control (gain 0 or 1)
  readonly analyser: AnalyserNode;
  muted: boolean;
  solo: boolean;
  soloIsolate: boolean;
};

export type MasterBus = {
  readonly inputGain: GainNode;
  readonly faderGain: GainNode;
  readonly limiter: DynamicsCompressorNode; // INV-2: Non-bypassable brickwall limiter
  readonly analyser: AnalyserNode;
};

export type MixerEngine = {
  getOrCreateStrip(trackId: string): ChannelStrip;
  removeStrip(trackId: string): void;
  getStrip(trackId: string): ChannelStrip | undefined;
  getAllStrips(): readonly ChannelStrip[];
  getMaster(): MasterBus;
  setFaderLevel(trackId: string, level: number): void;
  setPan(trackId: string, pan: number): void;
  setMute(trackId: string, muted: boolean): void;
  setSolo(trackId: string, solo: boolean): void;
  setSoloIsolate(trackId: string, enabled: boolean): void;
  setMasterLevel(level: number): void;
  updateSoloState(): void;
  getTrackInput(trackId: string): AudioNode;
  addInsert(trackId: string, id: string, input: AudioNode, output: AudioNode): void;
  replaceInsert(trackId: string, id: string, input: AudioNode, output: AudioNode): void;
  removeInsert(trackId: string, insertId: string): void;
  emergencyMute(): void;
  releaseEmergencyMute(): void;
  dispose(): void;
};

export function createMixerEngine(ctx: AudioContext): MixerEngine
```

**Architecture:**
- Chain: inputGain → inserts → preFaderTap → faderGain → panner → muteGain → analyser → master
- INV-2: Master has non-bypassable DynamicsCompressor (threshold=-1dBFS, ratio=20:1, knee=0, attack=0.001s, release=0.01s)
- Solo logic: Solo-in-place with solo-isolate support

