1	/**
2	 * AudioContext lifecycle management.
3	 * Handles creation, suspension, resumption on user gesture,
4	 * and AudioWorklet module loading.
5	 */
6	
7	export type AudioEngineState =
8	  | "uninitialized"
9	  | "suspended"
10	  | "running"
11	  | "closed";
12	
13	export type AudioEngineContext = {
14	  readonly ctx: AudioContext;
15	  readonly state: AudioEngineState;
16	  resume: () => Promise<void>;
17	  close: () => Promise<void>;
18	  loadWorkletModule: (url: string) => Promise<void>;
19	};
20	
21	/**
22	 * Creates an AudioContext in suspended state.
23	 * Call resume() after a user gesture to start audio.
24	 */
25	export function createAudioEngine(): AudioEngineContext {
26	  const ctx = new AudioContext();
27	
28	  const engine: AudioEngineContext = {
29	    ctx,
30	    get state(): AudioEngineState {
31	      switch (ctx.state) {
32	        case "suspended":
33	          return "suspended";
34	        case "running":
35	          return "running";
36	        case "closed":
37	          return "closed";
38	        default:
39	          return "uninitialized";
40	      }
41	    },
42	    async resume(): Promise<void> {
43	      if (ctx.state === "suspended") {
44	        await ctx.resume();
45	      }
46	    },
47	    async close(): Promise<void> {
48	      if (ctx.state !== "closed") {
49	        await ctx.close();
50	      }
51	    },
52	    async loadWorkletModule(url: string): Promise<void> {
53	      await ctx.audioWorklet.addModule(url);
54	    },
55	  };
56	
57	  return engine;
58	}
59

1	/**
2	 * Transport state machine with cursor tracking.
3	 * Writes cursor position, state, and BPM to SharedArrayBuffer
4	 * for lock-free audio-thread <-> UI-thread communication.
5	 */
6	
7	import { createTempoMap, type TempoMap } from "./tempo-map";
8	import { TransportLayout } from "./shared-buffer-layout";
9	
10	export type TransportState = "stopped" | "playing" | "paused";
11	
12	const STATE_STOPPED = 0;
13	const STATE_PLAYING = 1;
14	const STATE_PAUSED = 2;
15	
16	export type LoopRegion = {
17	  readonly enabled: boolean;
18	  readonly start: number;
19	  readonly end: number;
20	};
21	
22	export type TransportClock = {
23	  readonly state: TransportState;
24	  play(): void;
25	  pause(): void;
26	  stop(): void;
27	  seek(seconds: number): void;
28	  setBpm(bpm: number): void;
29	  setLoop(region: LoopRegion): void;
30	  getLoop(): LoopRegion;
31	  /** Pure read — computes current cursor position without side effects. */
32	  getCursorSeconds(): number;
33	  /** Advances playback state: handles loop wrap, writes SAB. Call from scheduler. */
34	  updateCursor(): number;
35	  /** Returns true if the last updateCursor() call triggered a loop wrap. */
36	  didLoopWrap(): boolean;
37	  getTempoMap(): TempoMap;
38	  dispose(): void;
39	};
40	
41	export function createTransportClock(
42	  ctx: AudioContext,
43	  transportSAB: SharedArrayBuffer,
44	  initialBpm = 120,
45	  sampleRate?: number,
46	): TransportClock {
47	  const rate = sampleRate ?? ctx.sampleRate;
48	
49	  // SAB views -- created once (zero-allocation convention INV-3)
50	  const cursorView = new Float64Array(
51	    transportSAB,
52	    TransportLayout.CURSOR_SECONDS,
53	    1,
54	  );
55	  const stateView = new Uint8Array(transportSAB, TransportLayout.STATE, 1);
56	  const bpmView = new Float32Array(transportSAB, TransportLayout.BPM, 1);
57	
58	  let currentState: TransportState = "stopped";
59	  let cursorSeconds = 0;
60	  let playStartContextTime = 0;
61	  let playStartCursorSeconds = 0;
62	  let tempoMap = createTempoMap(
63	    initialBpm,
64	    { numerator: 4, denominator: 4 },
65	    rate,
66	  );
67	  let loop: LoopRegion = { enabled: false, start: 0, end: 0 };
68	  let loopWrapped = false;
69	
70	  // Write initial values to SAB
71	  stateView[0] = STATE_STOPPED;
72	  bpmView[0] = initialBpm;
73	  cursorView[0] = 0;
74	
75	  function writeSABState(state: number): void {
76	    stateView[0] = state;
77	  }
78	
79	  function writeSABCursor(seconds: number): void {
80	    cursorView[0] = seconds;
81	  }
82	
83	  const clock: TransportClock = {
84	    get state(): TransportState {
85	      return currentState;
86	    },
87	
88	    play(): void {
89	      if (currentState === "playing") return;
90	
91	      playStartContextTime = ctx.currentTime;
92	      playStartCursorSeconds = cursorSeconds;
93	      currentState = "playing";
94	      writeSABState(STATE_PLAYING);
95	    },
96	
97	    pause(): void {
98	      if (currentState !== "playing") return;
99	
100	      cursorSeconds =
101	        playStartCursorSeconds + (ctx.currentTime - playStartContextTime);
102	      currentState = "paused";
103	      writeSABState(STATE_PAUSED);
104	      writeSABCursor(cursorSeconds);
105	    },
106	
107	    stop(): void {
108	      if (currentState === "stopped") return;
109	
110	      cursorSeconds = 0;
111	      currentState = "stopped";
112	      writeSABState(STATE_STOPPED);
113	      writeSABCursor(0);
114	    },
115	
116	    seek(seconds: number): void {
117	      const clamped = Math.max(0, seconds);
118	      cursorSeconds = clamped;
119	      if (currentState === "playing") {
120	        playStartContextTime = ctx.currentTime;
121	        playStartCursorSeconds = clamped;
122	      }
123	      writeSABCursor(clamped);
124	    },
125	
126	    setBpm(bpm: number): void {
127	      const clamped = Math.min(999, Math.max(20, bpm));
128	      tempoMap = createTempoMap(clamped, tempoMap.timeSignature, rate);
129	      bpmView[0] = clamped;
130	    },
131	
132	    setLoop(region: LoopRegion): void {
133	      loop = region;
134	    },
135	
136	    getLoop(): LoopRegion {
137	      return loop;
138	    },
139	
140	    getCursorSeconds(): number {
141	      if (currentState === "playing") {
142	        const elapsed = ctx.currentTime - playStartContextTime;
143	        let pos = playStartCursorSeconds + elapsed;
144	
145	        // Apply loop wrap (pure computation, no mutation)
146	        if (loop.enabled && loop.end > loop.start && pos >= loop.end) {
147	          const loopLen = loop.end - loop.start;
148	          pos = loop.start + ((pos - loop.start) % loopLen);
149	        }
150	
151	        return pos;
152	      }
153	      return cursorSeconds;
154	    },
155	
156	    updateCursor(): number {
157	      loopWrapped = false;
158	      if (currentState === "playing") {
159	        const elapsed = ctx.currentTime - playStartContextTime;
160	        let pos = playStartCursorSeconds + elapsed;
161	
162	        if (loop.enabled && loop.end > loop.start && pos >= loop.end) {
163	          const loopLen = loop.end - loop.start;
164	          pos = loop.start + ((pos - loop.start) % loopLen);
165	          playStartContextTime = ctx.currentTime;
166	          playStartCursorSeconds = pos;
167	          loopWrapped = true;
168	        }
169	
170	        cursorSeconds = pos;
171	        writeSABCursor(pos);
172	        return pos;
173	      }
174	      return cursorSeconds;
175	    },
176	
177	    didLoopWrap(): boolean {
178	      return loopWrapped;
179	    },
180	
181	    getTempoMap(): TempoMap {
182	      return tempoMap;
183	    },
184	
185	    dispose(): void {
186	      currentState = "stopped";
187	      writeSABState(STATE_STOPPED);
188	    },
189	  };
190	
191	  return clock;
192	}
193

1	/**
2	 * Mixer audio graph engine.
3	 * Per-track channel strips -> master bus -> brickwall limiter -> destination.
4	 *
5	 * INV-2: Non-bypassable DynamicsCompressorNode as brickwall limiter
6	 * (threshold=-1dBFS, ratio=20:1, knee=0, attack=0.001s)
7	 */
8	
9	import type { ChannelStrip, MasterBus, MixerEngine } from "./types";
10	import { createInsertChain, type InsertChain } from "./insert-chain";
11	import { faderTaper } from "./fader-taper";
12	
13	function clamp(v: number, min: number, max: number): number {
14	  return Math.min(max, Math.max(min, v));
15	}
16	
17	function createMasterBus(ctx: AudioContext): MasterBus {
18	  const inputGain = ctx.createGain();
19	  const faderGain = ctx.createGain();
20	  const limiter = ctx.createDynamicsCompressor();
21	  const analyser = ctx.createAnalyser();
22	
23	  // INV-2: Brickwall limiter settings
24	  limiter.threshold.value = -1;
25	  limiter.ratio.value = 20;
26	  limiter.knee.value = 0;
27	  limiter.attack.value = 0.001;
28	  limiter.release.value = 0.01;
29	
30	  // Chain: inputGain -> faderGain -> limiter -> analyser -> destination
31	  inputGain.connect(faderGain);
32	  faderGain.connect(limiter);
33	  limiter.connect(analyser);
34	  analyser.connect(ctx.destination);
35	
36	  return { inputGain, faderGain, limiter, analyser };
37	}
38	
39	function createChannelStrip(
40	  ctx: AudioContext,
41	  trackId: string,
42	  masterInput: GainNode,
43	): ChannelStrip {
44	  const inputGain = ctx.createGain();
45	  const preFaderTap = ctx.createGain(); // Unity gain tap for pre-fader sends
46	  const faderGain = ctx.createGain();
47	  const panner = ctx.createStereoPanner();
48	  const muteGain = ctx.createGain();
49	  const analyser = ctx.createAnalyser();
50	
51	  // Chain: inputGain -> [insert chain] -> preFaderTap -> faderGain -> panner -> muteGain -> analyser -> master input
52	  // Note: inputGain -> preFaderTap connection is managed by the insert chain
53	  preFaderTap.connect(faderGain);
54	  faderGain.connect(panner);
55	  panner.connect(muteGain);
56	  muteGain.connect(analyser);
57	  analyser.connect(masterInput);
58	
59	  return {
60	    trackId,
61	    inputGain,
62	    inserts: [],
63	    preFaderTap,
64	    faderGain,
65	    panner,
66	    muteGain,
67	    analyser,
68	    muted: false,
69	    solo: false,
70	    soloIsolate: false,
71	  };
72	}
73	
74	export function createMixerEngine(ctx: AudioContext): MixerEngine {
75	  const master = createMasterBus(ctx);
76	  const strips = new Map<string, ChannelStrip>();
77	  const insertChains = new Map<string, InsertChain>();
78	  let savedMasterLevel = 1;
79	
80	  function applyMuteState(strip: ChannelStrip): void {
81	    const hasSolo = [...strips.values()].some((s) => s.solo);
82	
83	    if (strip.muted) {
84	      strip.muteGain.gain.value = 0;
85	      return;
86	    }
87	
88	    if (hasSolo) {
89	      if (strip.solo || strip.soloIsolate) {
90	        strip.muteGain.gain.value = 1;
91	      } else {
92	        strip.muteGain.gain.value = 0;
93	      }
94	    } else {
95	      strip.muteGain.gain.value = 1;
96	    }
97	  }
98	
99	  const engine: MixerEngine = {
100	    getOrCreateStrip(trackId: string): ChannelStrip {
101	      const existing = strips.get(trackId);
102	      if (existing) return existing;
103	
104	      const strip = createChannelStrip(ctx, trackId, master.inputGain);
105	      strips.set(trackId, strip);
106	      // Insert chain between inputGain and preFaderTap
107	      const chain = createInsertChain(strip.inputGain, strip.preFaderTap);
108	      insertChains.set(trackId, chain);
109	      return strip;
110	    },
111	
112	    removeStrip(trackId: string): void {
113	      const strip = strips.get(trackId);
114	      if (!strip) return;
115	
116	      const chain = insertChains.get(trackId);
117	      chain?.dispose();
118	      insertChains.delete(trackId);
119	
120	      strip.inputGain.disconnect();
121	      strip.preFaderTap.disconnect();
122	      strip.faderGain.disconnect();
123	      strip.panner.disconnect();
124	      strip.muteGain.disconnect();
125	      strip.analyser.disconnect();
126	      strips.delete(trackId);
127	    },
128	
129	    getStrip(trackId: string): ChannelStrip | undefined {
130	      return strips.get(trackId);
131	    },
132	
133	    getAllStrips(): readonly ChannelStrip[] {
134	      return [...strips.values()];
135	    },
136	
137	    getMaster(): MasterBus {
138	      return master;
139	    },
140	
141	    setFaderLevel(trackId: string, level: number): void {
142	      const strip = strips.get(trackId);
143	      if (!strip) return;
144	      const clamped = clamp(level, 0, 2);
145	      strip.faderGain.gain.value = faderTaper(clamped);
146	    },
147	
148	    setPan(trackId: string, pan: number): void {
149	      const strip = strips.get(trackId);
150	      if (!strip) return;
151	      strip.panner.pan.value = clamp(pan, -1, 1);
152	    },
153	
154	    setMute(trackId: string, muted: boolean): void {
155	      const strip = strips.get(trackId);
156	      if (!strip) return;
157	      strip.muted = muted;
158	      applyMuteState(strip);
159	    },
160	
161	    setSolo(trackId: string, solo: boolean): void {
162	      const strip = strips.get(trackId);
163	      if (!strip) return;
164	      strip.solo = solo;
165	      engine.updateSoloState();
166	    },
167	
168	    setSoloIsolate(trackId: string, enabled: boolean): void {
169	      const strip = strips.get(trackId);
170	      if (!strip) return;
171	      strip.soloIsolate = enabled;
172	      engine.updateSoloState();
173	    },
174	
175	    updateSoloState(): void {
176	      for (const strip of strips.values()) {
177	        applyMuteState(strip);
178	      }
179	    },
180	
181	    setMasterLevel(level: number): void {
182	      savedMasterLevel = clamp(level, 0, 2);
183	      master.faderGain.gain.value = savedMasterLevel;
184	    },
185	
186	    getTrackInput(trackId: string): AudioNode {
187	      return engine.getOrCreateStrip(trackId).inputGain;
188	    },
189	
190	    addInsert(
191	      trackId: string,
192	      id: string,
193	      input: AudioNode,
194	      output: AudioNode,
195	    ): void {
196	      const chain = insertChains.get(trackId);
197	      chain?.addInsert(id, input, output);
198	    },
199	
200	    replaceInsert(
201	      trackId: string,
202	      id: string,
203	      input: AudioNode,
204	      output: AudioNode,
205	    ): void {
206	      const chain = insertChains.get(trackId);
207	      chain?.replaceInsert(id, input, output);
208	    },
209	
210	    removeInsert(trackId: string, insertId: string): void {
211	      const chain = insertChains.get(trackId);
212	      chain?.removeInsert(insertId);
213	    },
214	
215	    emergencyMute(): void {
216	      master.faderGain.gain.value = 0;
217	    },
218	
219	    releaseEmergencyMute(): void {
220	      master.faderGain.gain.value = savedMasterLevel;
221	    },
222	
223	    dispose(): void {
224	      for (const chain of insertChains.values()) {
225	        chain.dispose();
226	      }
227	      insertChains.clear();
228	      for (const strip of strips.values()) {
229	        strip.inputGain.disconnect();
230	        strip.preFaderTap.disconnect();
231	        strip.faderGain.disconnect();
232	        strip.panner.disconnect();
233	        strip.muteGain.disconnect();
234	        strip.analyser.disconnect();
235	      }
236	      strips.clear();
237	      master.inputGain.disconnect();
238	      master.faderGain.disconnect();
239	      master.limiter.disconnect();
240	      master.analyser.disconnect();
241	    },
242	  };
243	
244	  return engine;
245	}
246

1	/**
2	 * SynthInstrument: main-thread controller for the synth AudioWorklet.
3	 * Creates AudioWorkletNode, sends voice commands, manages parameters,
4	 * connects output to mixer channel strip.
5	 *
6	 * R-EVT-08: Real-time parameter changes via MessagePort.
7	 */
8	
9	import type { SynthVoiceCommand, SynthParameterMap } from "./synth-types";
10	import {
11	  DEFAULT_SYNTH_PARAMS,
12	  WAVEFORM_TYPES,
13	  FILTER_TYPES,
14	  LFO_SHAPES,
15	} from "./synth-types";
16	import type { MixerEngine } from "@audio/mixer/types";
17	import type { WorkletModRoute } from "./modulation-engine";
18	
19	export type SynthInstrument = {
20	  /** The audio output node — connect to mixer channel strip. */
21	  readonly output: AudioNode;
22	  /** Current parameter values. */
23	  readonly params: Readonly<SynthParameterMap>;
24	  /** Send a note-on to the synth. */
25	  noteOn(note: number, velocity: number, legato?: boolean): void;
26	  /** Send a note-off to the synth. */
27	  noteOff(note: number): void;
28	  /** Release all notes. */
29	  allNotesOff(): void;
30	  /** Set a synth parameter (forwarded to worklet). */
31	  setParam<K extends keyof SynthParameterMap>(
32	    key: K,
33	    value: SynthParameterMap[K],
34	  ): void;
35	  /** Send modulation routes to the worklet. */
36	  setModRoutes(routes: WorkletModRoute[]): void;
37	  /** Set a modulation source value (aftertouch, modWheel, pitchBend). */
38	  setModSource(source: string, value: number): void;
39	  /** Connect to a mixer channel. */
40	  connectToMixer(mixer: MixerEngine, trackId: string): void;
41	  /** Disconnect from mixer. */
42	  disconnectFromMixer(mixer: MixerEngine, trackId: string): void;
43	  /** Clean up all resources. */
44	  dispose(): void;
45	};
46	
47	/** URL for the worklet processor module */
48	const PROCESSOR_URL = new URL("./synth-processor.ts", import.meta.url);
49	
50	/**
51	 * Create a SynthInstrument connected to the given AudioContext.
52	 * Must call `audioCtx.audioWorklet.addModule()` first via loadWorkletModule().
53	 */
54	export async function createSynthInstrument(
55	  ctx: AudioContext,
56	): Promise<SynthInstrument> {
57	  // Load the worklet module
58	  await ctx.audioWorklet.addModule(PROCESSOR_URL.href);
59	
60	  const node = new AudioWorkletNode(ctx, "synth-processor", {
61	    numberOfInputs: 0,
62	    numberOfOutputs: 1,
63	    outputChannelCount: [2],
64	  });
65	
66	  const params: SynthParameterMap = { ...DEFAULT_SYNTH_PARAMS };
67	
68	  function postCommand(cmd: SynthVoiceCommand): void {
69	    node.port.postMessage(cmd);
70	  }
71	
72	  const instrument: SynthInstrument = {
73	    output: node,
74	    params,
75	
76	    noteOn(note: number, velocity: number, legato = false): void {
77	      postCommand({ type: "noteOn", note, velocity, legato });
78	    },
79	
80	    noteOff(note: number): void {
81	      postCommand({ type: "noteOff", note });
82	    },
83	
84	    allNotesOff(): void {
85	      postCommand({ type: "allNotesOff" });
86	    },
87	
88	    setParam<K extends keyof SynthParameterMap>(
89	      key: K,
90	      value: SynthParameterMap[K],
91	    ): void {
92	      (params as Record<string, unknown>)[key] = value;
93	
94	      // Map enum types to numeric index for the worklet
95	      let numericValue: number;
96	      if (typeof value === "string") {
97	        // Lookup string in appropriate type array
98	        switch (key) {
99	          case "osc1Type":
100	          case "osc2Type":
101	            numericValue = WAVEFORM_TYPES.indexOf(
102	              value as (typeof WAVEFORM_TYPES)[number],
103	            );
104	            break;
105	          case "filterType":
106	            numericValue = FILTER_TYPES.indexOf(
107	              value as (typeof FILTER_TYPES)[number],
108	            );
109	            break;
110	          case "lfo1Shape":
111	          case "lfo2Shape":
112	            numericValue = LFO_SHAPES.indexOf(
113	              value as (typeof LFO_SHAPES)[number],
114	            );
115	            break;
116	          default:
117	            numericValue = 0;
118	        }
119	      } else {
120	        numericValue = value;
121	      }
122	
123	      postCommand({
124	        type: "setParam",
125	        key: key as string,
126	        value: numericValue,
127	      });
128	    },
129	
130	    setModRoutes(routes: WorkletModRoute[]): void {
131	      postCommand({ type: "setModRoutes", routes });
132	    },
133	
134	    setModSource(source: string, value: number): void {
135	      postCommand({ type: "setModSource", source, value });
136	    },
137	
138	    connectToMixer(mixer: MixerEngine, trackId: string): void {
139	      const strip = mixer.getOrCreateStrip(trackId);
140	      node.connect(strip.inputGain);
141	    },
142	
143	    disconnectFromMixer(_mixer: MixerEngine, _trackId: string): void {
144	      node.disconnect();
145	    },
146	
147	    dispose(): void {
148	      node.disconnect();
149	      node.port.close();
150	    },
151	  };
152	
153	  return instrument;
154	}
