22	export function createInMemorySessionStorage(): SessionStorage {
23	  const active = new Map<string, string>();
24	  const saved = new Map<
25	    string,
26	    { name: string; json: string; updatedAt: number }
27	  >();
28	
29	  return {
30	    getDraft(): Promise<string | undefined> {
31	      return Promise.resolve(active.get("draft"));
32	    },
33	    putDraft(json): Promise<void> {
34	      active.set("draft", json);
35	      return Promise.resolve();
36	    },
37	    deleteDraft(): Promise<void> {
38	      active.delete("draft");
39	      return Promise.resolve();
40	    },
41	    getCurrent(): Promise<string | undefined> {
42	      return Promise.resolve(active.get("current"));
43	    },
44	    putCurrent(json): Promise<void> {
45	      active.set("current", json);
46	      return Promise.resolve();
47	    },
48	    getBackup(): Promise<string | undefined> {
49	      return Promise.resolve(active.get("backup"));
50	    },
51	    putBackup(json): Promise<void> {
52	      active.set("backup", json);
53	      return Promise.resolve();
54	    },
55	    listSessions(): Promise<SessionListEntry[]> {
56	      return Promise.resolve(
57	        [...saved.entries()].map(([id, entry]) => ({
58	          id,
59	          name: entry.name,
60	          updatedAt: entry.updatedAt,
61	        })),
62	      );
63	    },
64	    getSession(id): Promise<string | undefined> {
65	      return Promise.resolve(saved.get(id)?.json);
66	    },
67	    putSession(id, name, json): Promise<void> {
68	      saved.set(id, { name, json, updatedAt: Date.now() });
69	      return Promise.resolve();
70	    },
71	    deleteSession(id): Promise<void> {
72	      saved.delete(id);
73	      return Promise.resolve();
74	    },
75	    renameSession(id, name): Promise<void> {
76	      const entry = saved.get(id);
77	      if (entry !== undefined) {
78	        entry.name = name;
79	      }
