  return { id: "track-1", name: "Track 1", type: "audio", /* ... */ };
}

beforeEach(() => {
  useDawStore.setState({
    tracks: [],
    clips: {},
    masterVolume: 1,
  });
});

it("toggles mute on button click", () => {
  useDawStore.setState({ tracks: [makeTrack({ id: "t1" })] });
  render(<MixerPanel />);
  fireEvent.click(screen.getByLabelText("Mute"));
  expect(useDawStore.getState().tracks[0]?.muted).toBe(true);
});
```

**Key characteristics:**
- Factory functions for test data (`makeTrack`)
- Store state manipulation via `setState()`
- Direct state verification post-action
- Uses `testId` attributes for rendering assertions
- `fireEvent` for user interactions

**SynthEditor pattern:**
```typescript
beforeEach(() => {
  useSynthStore.setState({ synths: {} });
  useSynthStore.getState().initSynth(trackId);
});

it("virtual keyboard triggers note callbacks", () => {
  const onNoteOn = vi.fn();
  const onNoteOff = vi.fn();
  render(
    <SynthEditor
      trackId={trackId}
      onNoteOn={onNoteOn}
      onNoteOff={onNoteOff}
    />,
  );
  fireEvent.mouseDown(screen.getByTestId("key-48"));
  expect(onNoteOn).toHaveBeenCalledWith(48, 100);
});
```

### Summary of Setup/Teardown Conventions

| Level | Pattern |
|-------|---------|
| **Global mocks** | `vi.stubGlobal()` + `vi.restoreAllMocks()` |
| **Component state** | Store `.setState()` in `beforeEach()` |
| **Store cleanup** | Via state reset, not explicit cleanup functions |
| **Component unmount** | `cleanup()` from `@testing-library/react` in `afterEach()` |
| **Module imports** | `vi.resetModules()` for AudioWorklet tests |
| **Test data** | Factory functions like `makeTrack()` |
| **Assertions** | Direct state queries (`useDawStore.getState()`) |
| **Async tests** | `await act()` wrapper for state updates |

