Here's the complete API surface for the BRUTALWAV integration test harness:

## 1. engine-context.ts

```typescript
export type AudioEngineState =
  | "uninitialized"
  | "suspended"
  | "running"
  | "closed";

export type AudioEngineContext = {
  readonly ctx: AudioContext;
  readonly state: AudioEngineState;
  resume: () => Promise<void>;
  close: () => Promise<void>;
  loadWorkletModule: (url: string) => Promise<void>;
};

export function createAudioEngine(): AudioEngineContext
```

## 2. transport-clock.ts

```typescript
export type TransportState = "stopped" | "playing" | "paused";

export type LoopRegion = {
  readonly enabled: boolean;
  readonly start: number;
  readonly end: number;
};

export type TransportClock = {
  readonly state: TransportState;
  play(): void;
  pause(): void;
  stop(): void;
  seek(seconds: number): void;
  setBpm(bpm: number): void;
  setLoop(region: LoopRegion): void;
  getLoop(): LoopRegion;
  getCursorSeconds(): number;
  updateCursor(): number;
  didLoopWrap(): boolean;
  getTempoMap(): TempoMap;
  dispose(): void;
};

export function createTransportClock(
  ctx: AudioContext,
  transportSAB: SharedArrayBuffer,
  initialBpm = 120,
  sampleRate?: number,
): TransportClock
```

## 3. mixer-engine.ts

```typescript
export function createMixerEngine(ctx: AudioContext): MixerEngine

export type MixerEngine = {
  getOrCreateStrip(trackId: string): ChannelStrip;
  removeStrip(trackId: string): void;
