1	/**
2	 * Mixer audio graph engine.
3	 * Per-track channel strips -> master bus -> brickwall limiter -> destination.
4	 *
5	 * INV-2: Non-bypassable DynamicsCompressorNode as brickwall limiter
6	 * (threshold=-1dBFS, ratio=20:1, knee=0, attack=0.001s)
7	 */
8	
9	import type { ChannelStrip, MasterBus, MixerEngine } from "./types";
10	import { createInsertChain, type InsertChain } from "./insert-chain";
11	import { faderTaper } from "./fader-taper";
12	
13	function clamp(v: number, min: number, max: number): number {
14	  return Math.min(max, Math.max(min, v));
15	}
16	
17	function createMasterBus(ctx: AudioContext): MasterBus {
18	  const inputGain = ctx.createGain();
19	  const faderGain = ctx.createGain();
20	  const limiter = ctx.createDynamicsCompressor();
21	  const analyser = ctx.createAnalyser();
22	
23	  // INV-2: Brickwall limiter settings
24	  limiter.threshold.value = -1;
25	  limiter.ratio.value = 20;
26	  limiter.knee.value = 0;
27	  limiter.attack.value = 0.001;
28	  limiter.release.value = 0.01;
29	
30	  // Chain: inputGain -> faderGain -> limiter -> analyser -> destination
31	  inputGain.connect(faderGain);
32	  faderGain.connect(limiter);
33	  limiter.connect(analyser);
34	  analyser.connect(ctx.destination);
35	
36	  return { inputGain, faderGain, limiter, analyser };
37	}
38	
39	function createChannelStrip(
40	  ctx: AudioContext,
41	  trackId: string,
42	  masterInput: GainNode,
43	): ChannelStrip {
44	  const inputGain = ctx.createGain();
45	  const preFaderTap = ctx.createGain(); // Unity gain tap for pre-fader sends
46	  const faderGain = ctx.createGain();
47	  const panner = ctx.createStereoPanner();
48	  const muteGain = ctx.createGain();
49	  const analyser = ctx.createAnalyser();
50	
51	  // Chain: inputGain -> [insert chain] -> preFaderTap -> faderGain -> panner -> muteGain -> analyser -> master input
52	  // Note: inputGain -> preFaderTap connection is managed by the insert chain
53	  preFaderTap.connect(faderGain);
54	  faderGain.connect(panner);
55	  panner.connect(muteGain);
56	  muteGain.connect(analyser);
57	  analyser.connect(masterInput);
58	
59	  return {
60	    trackId,
61	    inputGain,
62	    inserts: [],
63	    preFaderTap,
64	    faderGain,
65	    panner,
66	    muteGain,
67	    analyser,
68	    muted: false,
69	    solo: false,
70	    soloIsolate: false,
71	  };
72	}
73	
74	export function createMixerEngine(ctx: AudioContext): MixerEngine {
75	  const master = createMasterBus(ctx);
76	  const strips = new Map<string, ChannelStrip>();
77	  const insertChains = new Map<string, InsertChain>();
78	  let savedMasterLevel = 1;
79	
80	  function applyMuteState(strip: ChannelStrip): void {
81	    const hasSolo = [...strips.values()].some((s) => s.solo);
82	
83	    if (strip.muted) {
84	      strip.muteGain.gain.value = 0;
85	      return;
86	    }
87	
88	    if (hasSolo) {
89	      if (strip.solo || strip.soloIsolate) {
90	        strip.muteGain.gain.value = 1;
91	      } else {
92	        strip.muteGain.gain.value = 0;
93	      }
94	    } else {
95	      strip.muteGain.gain.value = 1;
96	    }
97	  }
98	
99	  const engine: MixerEngine = {
100	    getOrCreateStrip(trackId: string): ChannelStrip {
101	      const existing = strips.get(trackId);
102	      if (existing) return existing;
103	
104	      const strip = createChannelStrip(ctx, trackId, master.inputGain);
105	      strips.set(trackId, strip);
106	      // Insert chain between inputGain and preFaderTap
107	      const chain = createInsertChain(strip.inputGain, strip.preFaderTap);
108	      insertChains.set(trackId, chain);
109	      return strip;
110	    },
111	
112	    removeStrip(trackId: string): void {
113	      const strip = strips.get(trackId);
114	      if (!strip) return;
115	
116	      const chain = insertChains.get(trackId);
117	      chain?.dispose();
118	      insertChains.delete(trackId);
119	
120	      strip.inputGain.disconnect();
121	      strip.preFaderTap.disconnect();
122	      strip.faderGain.disconnect();
123	      strip.panner.disconnect();
124	      strip.muteGain.disconnect();
125	      strip.analyser.disconnect();
126	      strips.delete(trackId);
127	    },
128	
129	    getStrip(trackId: string): ChannelStrip | undefined {
130	      return strips.get(trackId);
131	    },
132	
133	    getAllStrips(): readonly ChannelStrip[] {
134	      return [...strips.values()];
135	    },
136	
137	    getMaster(): MasterBus {
138	      return master;
139	    },
140	
141	    setFaderLevel(trackId: string, level: number): void {
142	      const strip = strips.get(trackId);
143	      if (!strip) return;
144	      const clamped = clamp(level, 0, 2);
145	      strip.faderGain.gain.value = faderTaper(clamped);
146	    },
147	
148	    setPan(trackId: string, pan: number): void {
149	      const strip = strips.get(trackId);
150	      if (!strip) return;
151	      strip.panner.pan.value = clamp(pan, -1, 1);
152	    },
153	
154	    setMute(trackId: string, muted: boolean): void {
155	      const strip = strips.get(trackId);
156	      if (!strip) return;
157	      strip.muted = muted;
158	      applyMuteState(strip);
159	    },
160	
161	    setSolo(trackId: string, solo: boolean): void {
162	      const strip = strips.get(trackId);
163	      if (!strip) return;
164	      strip.solo = solo;
165	      engine.updateSoloState();
166	    },
167	
168	    setSoloIsolate(trackId: string, enabled: boolean): void {
169	      const strip = strips.get(trackId);
170	      if (!strip) return;
171	      strip.soloIsolate = enabled;
172	      engine.updateSoloState();
173	    },
174	
175	    updateSoloState(): void {
176	      for (const strip of strips.values()) {
177	        applyMuteState(strip);
178	      }
179	    },
180	
181	    setMasterLevel(level: number): void {
182	      savedMasterLevel = clamp(level, 0, 2);
183	      master.faderGain.gain.value = savedMasterLevel;
184	    },
185	
186	    getTrackInput(trackId: string): AudioNode {
187	      return engine.getOrCreateStrip(trackId).inputGain;
188	    },
189	
190	    addInsert(
191	      trackId: string,
192	      id: string,
193	      input: AudioNode,
194	      output: AudioNode,
195	    ): void {
196	      const chain = insertChains.get(trackId);
197	      chain?.addInsert(id, input, output);
198	    },
199	
200	    replaceInsert(
201	      trackId: string,
202	      id: string,
203	      input: AudioNode,
204	      output: AudioNode,
205	    ): void {
206	      const chain = insertChains.get(trackId);
207	      chain?.replaceInsert(id, input, output);
208	    },
209	
210	    removeInsert(trackId: string, insertId: string): void {
211	      const chain = insertChains.get(trackId);
212	      chain?.removeInsert(insertId);
213	    },
214	
215	    emergencyMute(): void {
216	      master.faderGain.gain.value = 0;
217	    },
218	
219	    releaseEmergencyMute(): void {
220	      master.faderGain.gain.value = savedMasterLevel;
221	    },
222	
223	    dispose(): void {
224	      for (const chain of insertChains.values()) {
225	        chain.dispose();
226	      }
227	      insertChains.clear();
228	      for (const strip of strips.values()) {
229	        strip.inputGain.disconnect();
230	        strip.preFaderTap.disconnect();
231	        strip.faderGain.disconnect();
232	        strip.panner.disconnect();
233	        strip.muteGain.disconnect();
234	        strip.analyser.disconnect();
235	      }
236	      strips.clear();
237	      master.inputGain.disconnect();
238	      master.faderGain.disconnect();
239	      master.limiter.disconnect();
240	      master.analyser.disconnect();
241	    },
242	  };
243	
244	  return engine;
245	}
