38	  effects: effectsSectionSchema.optional(),
39	  modulation: modulationSectionSchema.optional(),
40	  arpeggiator: arpeggiatorSectionSchema.optional(),
41	  automation: automationSectionSchema.optional(),
42	});
43	
44	export type SessionSchema = z.infer<typeof sessionSchema>;
45	
46	export function createDefaultSession(): SessionSchema {
47	  const now = Date.now();
48	  return {
49	    version: SESSION_VERSION,
50	    meta: { name: "Untitled", createdAt: now, updatedAt: now },
51	    transport: { bpm: 120, loopEnabled: false, loopStart: 0, loopEnd: 0 },
52	    tracks: [],
53	    clips: [],
54	    mixer: { masterVolume: 1 },
55	  };
56	}
57

