658	        const blob = encodeRenderedBuffer(renderedBuffer, options.bitDepth);
659	
660	        yield {
661	          phase: "complete",
662	          progress: 1,
663	          renderedSeconds: duration,
664	          totalSeconds: duration,
665	        };
666	
667	        return {
668	          blob,
669	          duration,
670	          sampleRate: options.sampleRate,
671	          channels: 2,
672	        };
673	      } finally {
