1	/**
2	 * Types for the bounce/export system.
3	 * Offline rendering of the session to WAV file.
4	 *
5	 * EARS: R-EVT-14, NFR-17
6	 * Exports: BounceEngine, BounceProgress
7	 */
8	
9	import type {
10	  AudioClipModel,
11	  MidiClipModel,
12	  TrackModel,
13	} from "@state/track/types";
14	import type { AutomationLane } from "@audio/automation/automation-types";
15	import type {
