/**
 * Zod schemas for arpeggiator state serialization.
 */

import { z } from "zod/v4";
import type { ArpParams } from "@audio/arpeggiator/arpeggiator-types";

export const arpParamsSchema = z.object({
  enabled: z.boolean(),
  pattern: z.enum(["up", "down", "up-down", "down-up", "random", "as-played"]),
  rateDivision: z.enum([
    "1/4",
    "1/8",
    "1/16",
    "1/32",
    "1/4t",
    "1/8t",
    "1/16t",
    "1/32t",
  ]),
  octaveRange: z.number().int().min(1).max(4),
  octaveDirection: z.enum(["up", "down", "up-down"]),
  gate: z.number().min(0.01).max(1),
  swing: z.number().min(0).max(1),
  latch: z.boolean(),
});

export const trackArpSchema = z.object({
  trackId: z.string(),
  params: arpParamsSchema,
});

export const arpeggiatorSectionSchema = z.array(trackArpSchema);

export type ArpeggiatorSectionSchema = z.infer<typeof arpeggiatorSectionSchema>;

// Compile-time check: ArpParams and arpParamsSchema stay in sync
type _SchemaType = z.infer<typeof arpParamsSchema>;
const _syncCheck: _SchemaType = null as unknown as ArpParams;
const _reverseCheck: ArpParams = null as unknown as _SchemaType;
void _syncCheck;
void _reverseCheck;

/**
 * Zod schemas for automation state serialization.
 */

import { z } from "zod/v4";

export const automationPointSchema = z.object({
  id: z.string(),
  time: z.number().min(0),
  value: z.number().min(0).max(1),
  interpolation: z.enum(["linear", "curved"]),
  curve: z.number().min(-1).max(1),
});

const mixerTargetSchema = z.object({
  type: z.literal("mixer"),
  param: z.enum(["volume", "pan"]),
});

const effectTargetSchema = z.object({
  type: z.literal("effect"),
  effectId: z.string(),
  paramKey: z.string(),
});

const synthTargetSchema = z.object({
  type: z.literal("synth"),
  paramKey: z.string(),
});

export const parameterTargetSchema = z.discriminatedUnion("type", [
  mixerTargetSchema,
  effectTargetSchema,
  synthTargetSchema,
]);

export const automationLaneSchema = z.object({
  id: z.string(),
  trackId: z.string(),
  target: parameterTargetSchema,
  points: z.array(automationPointSchema),
  mode: z.enum(["read", "write", "touch"]),
  armed: z.boolean(),
});

export const trackAutomationSchema = z.object({
  trackId: z.string(),
  lanes: z.array(automationLaneSchema),
});

export const automationSectionSchema = z.array(trackAutomationSchema);

export type AutomationSectionSchema = z.infer<typeof automationSectionSchema>;

import { z } from "zod/v4";

export const noteEventSchema = z.object({
  id: z.string(),
  pitch: z.number().int().min(0).max(127),
  velocity: z.number().int().min(0).max(127),
  startTime: z.number().min(0),
  duration: z.number().gt(0),
});

export const audioClipSchema = z.object({
  type: z.literal("audio"),
  id: z.string(),
  trackId: z.string(),
  sourceId: z.string(),
  startTime: z.number().min(0),
  sourceOffset: z.number().min(0),
  duration: z.number().min(0),
  gain: z.number().min(0).max(2),
  fadeIn: z.number().min(0),
  fadeOut: z.number().min(0),
  name: z.string(),
});

export const midiClipSchema = z.object({
  type: z.literal("midi"),
  id: z.string(),
  trackId: z.string(),
  startTime: z.number().min(0),
  duration: z.number().min(0),
  noteEvents: z.array(noteEventSchema),
  name: z.string(),
});

export const clipSchema = z.discriminatedUnion("type", [
  audioClipSchema,
  midiClipSchema,
]);

export type ClipSchema = z.infer<typeof clipSchema>;

export const trackSchema = z.object({
  id: z.string(),
  name: z.string(),
  type: z.enum(["audio", "instrument"]),
  color: z.string().regex(/^#[0-9a-fA-F]{6}$/),
  muted: z.boolean(),
  solo: z.boolean(),
  armed: z.boolean(),
  soloIsolate: z.boolean(),
  volume: z.number().min(0).max(2),
  pan: z.number().min(-1).max(1),
  clipIds: z.array(z.string()),
});

export type TrackSchema = z.infer<typeof trackSchema>;

