1	/**
2	 * Modulation matrix types and registries.
3	 * Defines sources, destinations, and routes for the modulation system.
4	 *
5	 * Exports: ModSource, ModDestination, ModRoute, ModulationMatrix
6	 */
7	
8	// ─── Source Registry ───
9	
10	export const MOD_SOURCES = [
11	  "lfo1",
12	  "lfo2",
13	  "ampEnv",
14	  "filterEnv",
15	  "velocity",
16	  "aftertouch",
17	  "modWheel",
18	  "pitchBend",
19	] as const;
20	
21	export type ModSource = (typeof MOD_SOURCES)[number];
22	
23	/** Per-voice sources have a different value per active voice */
24	export const PER_VOICE_SOURCES: ReadonlySet<ModSource> = new Set([
25	  "velocity",
26	  "ampEnv",
27	  "filterEnv",
28	]);
29	
30	// ─── Destination Registry ───
31	
32	export const MOD_DESTINATIONS = [
33	  "osc1Pitch",
34	  "osc2Pitch",
35	  "oscMix",
36	  "filterCutoff",
37	  "filterResonance",
38	  "ampLevel",
39	  "lfo1Rate",
40	  "lfo2Rate",
41	] as const;
42	
43	export type ModDestination = (typeof MOD_DESTINATIONS)[number];
44	
45	// ─── Route ───
46	
47	export type ModRoute = {
48	  readonly id: string;
49	  readonly source: ModSource;
50	  readonly destination: ModDestination;
51	  readonly amount: number; // -1..+1
52	  readonly bipolar: boolean;
53	};
54	
55	let routeCounter = 0;
56	
57	export function createModRoute(
58	  source: ModSource,
59	  destination: ModDestination,
60	  amount = 0,
61	  bipolar = true,
62	): ModRoute {
63	  return {
64	    id: `mod-${String(++routeCounter)}`,
65	    source,
66	    destination,
67	    amount: Math.max(-1, Math.min(1, amount)),
