/**
 * Shared test helpers for integration tests.
 * Provides mock AudioContext and factory functions for building
 * test data across multiple module boundaries.
 */

import type { TrackModel, AudioClipModel, MidiClipModel, MIDINoteEvent } from "@state/track/types";
import type { AutomationLane, AutomationPoint } from "@audio/automation/automation-types";
import type { EffectSlotState } from "@state/effects/types";
import type { ModRoute } from "@audio/synth/modulation-types";

// ─── Mock AudioContext ───

type MockAudioParam = {
  value: number;
  setValueAtTime: ReturnType<typeof vi.fn>;
  linearRampToValueAtTime: ReturnType<typeof vi.fn>;
  exponentialRampToValueAtTime: ReturnType<typeof vi.fn>;
  cancelScheduledValues: ReturnType<typeof vi.fn>;
};

function createMockParam(initial = 0): MockAudioParam {
  return {
    value: initial,
    setValueAtTime: vi.fn(function (this: MockAudioParam, v: number) {
      this.value = v;
    }),
    linearRampToValueAtTime: vi.fn(function (this: MockAudioParam, v: number) {
      this.value = v;
    }),
    exponentialRampToValueAtTime: vi.fn(function (this: MockAudioParam, v: number) {
      this.value = v;
    }),
    cancelScheduledValues: vi.fn(),
  };
}

type MockGainNode = {
  gain: MockAudioParam;
  connect: ReturnType<typeof vi.fn>;
  disconnect: ReturnType<typeof vi.fn>;
  channelCount: number;
};

type MockStereoPannerNode = {
  pan: MockAudioParam;
  connect: ReturnType<typeof vi.fn>;
  disconnect: ReturnType<typeof vi.fn>;
};

type MockAnalyserNode = {
  fftSize: number;
  connect: ReturnType<typeof vi.fn>;
  disconnect: ReturnType<typeof vi.fn>;
  getByteFrequencyData: ReturnType<typeof vi.fn>;
  getByteTimeDomainData: ReturnType<typeof vi.fn>;
  getFloatTimeDomainData: ReturnType<typeof vi.fn>;
};

type MockDynamicsCompressor = {
  threshold: MockAudioParam;
  ratio: MockAudioParam;
  knee: MockAudioParam;
  attack: MockAudioParam;
  release: MockAudioParam;
  connect: ReturnType<typeof vi.fn>;
  disconnect: ReturnType<typeof vi.fn>;
};

type MockBufferSource = {
  buffer: AudioBuffer | null;
  playbackRate: MockAudioParam;
  connect: ReturnType<typeof vi.fn>;
  disconnect: ReturnType<typeof vi.fn>;
  start: ReturnType<typeof vi.fn>;
  stop: ReturnType<typeof vi.fn>;
  onended: (() => void) | null;
};

export function createMockAudioContext(initialTime = 0): AudioContext {
  let _currentTime = initialTime;

  const ctx = {
    get currentTime() {
      return _currentTime;
    },
    sampleRate: 44100,
    state: "running" as AudioContextState,
    destination: {
      connect: vi.fn(),
      disconnect: vi.fn(),
      channelCount: 2,
    },
    createGain(): MockGainNode {
      const node: MockGainNode = {
        gain: createMockParam(1),
        connect: vi.fn().mockReturnThis(),
        disconnect: vi.fn(),
        channelCount: 2,
      };
      return node;
    },
    createStereoPanner(): MockStereoPannerNode {
      return {
        pan: createMockParam(0),
        connect: vi.fn().mockReturnThis(),
        disconnect: vi.fn(),
      };
    },
    createAnalyser(): MockAnalyserNode {
      return {
        fftSize: 2048,
        connect: vi.fn().mockReturnThis(),
        disconnect: vi.fn(),
        getByteFrequencyData: vi.fn(),
        getByteTimeDomainData: vi.fn(),
        getFloatTimeDomainData: vi.fn(),
      };
    },
    createDynamicsCompressor(): MockDynamicsCompressor {
      return {
        threshold: createMockParam(-24),
        ratio: createMockParam(12),
        knee: createMockParam(30),
        attack: createMockParam(0.003),
        release: createMockParam(0.25),
        connect: vi.fn().mockReturnThis(),
        disconnect: vi.fn(),
      };
    },
    createBufferSource(): MockBufferSource {
      return {
        buffer: null,
        playbackRate: createMockParam(1),
        connect: vi.fn().mockReturnThis(),
        disconnect: vi.fn(),
        start: vi.fn(),
        stop: vi.fn(),
        onended: null,
      };
    },
    createBuffer(channels: number, length: number, sampleRate: number): AudioBuffer {
      const channelData: Float32Array[] = [];
      for (let i = 0; i < channels; i++) {
        channelData.push(new Float32Array(length));
      }
      return {
        numberOfChannels: channels,
        length,
        sampleRate,
        duration: length / sampleRate,
        getChannelData(c: number) {
          return channelData[c]!;
        },
        copyToChannel(source: Float32Array, c: number) {
          channelData[c]!.set(source);
        },
        copyFromChannel: vi.fn(),
      } as unknown as AudioBuffer;
    },
    audioWorklet: {
      addModule: vi.fn().mockResolvedValue(undefined),
    },
    resume: vi.fn().mockResolvedValue(undefined),
    close: vi.fn().mockResolvedValue(undefined),
    // Test helper to advance time
    _advanceTime(seconds: number) {
      _currentTime += seconds;
    },
  };

  return ctx as unknown as AudioContext;
}

/** Advance the mock AudioContext's currentTime */
export function advanceTime(ctx: AudioContext, seconds: number): void {
  (ctx as unknown as { _advanceTime(s: number): void })._advanceTime(seconds);
}

// ─── Factory Functions ───

let idCounter = 0;

export function resetIdCounter(): void {
  idCounter = 0;
}

function nextId(prefix: string): string {
  return `${prefix}-${String(++idCounter)}`;
}

export function makeTrack(overrides: Partial<TrackModel> = {}): TrackModel {
  return {
    id: nextId("track"),
    name: "Test Track",
    type: "audio",
    color: "#FF5733",
    muted: false,
    solo: false,
    armed: false,
    soloIsolate: false,
    volume: 1,
    pan: 0,
    clipIds: [],
    ...overrides,
  };
}

export function makeAudioClip(overrides: Partial<AudioClipModel> = {}): AudioClipModel {
  return {
    type: "audio",
    id: nextId("clip"),
    trackId: "track-1",
    sourceId: "source-1",
    startTime: 0,
    sourceOffset: 0,
    duration: 2,
    gain: 1,
    fadeIn: 0,
    fadeOut: 0,
    name: "Test Clip",
    ...overrides,
  };
}

export function makeMidiClip(overrides: Partial<MidiClipModel> = {}): MidiClipModel {
  return {
    type: "midi",
    id: nextId("clip"),
    trackId: "track-1",
    startTime: 0,
    duration: 4,
    noteEvents: [],
    name: "MIDI Clip",
    ...overrides,
  };
}

export function makeNoteEvent(overrides: Partial<MIDINoteEvent> = {}): MIDINoteEvent {
  return {
    id: nextId("note"),
    pitch: 60,
    velocity: 100,
    startTime: 0,
    duration: 0.5,
    ...overrides,
  };
}

export function makeAutomationLane(overrides: Partial<AutomationLane> = {}): AutomationLane {
  return {
    id: nextId("lane"),
    trackId: "track-1",
    target: { type: "mixer", param: "volume" },
    points: [],
    mode: "read",
    armed: true,
    ...overrides,
  };
}

export function makeAutomationPoint(overrides: Partial<AutomationPoint> = {}): AutomationPoint {
  return {
    id: nextId("pt"),
    time: 0,
    value: 0.5,
    interpolation: "linear",
    curve: 0,
    ...overrides,
  };
}

export function makeEffectSlot(overrides: Partial<EffectSlotState> = {}): EffectSlotState {
  return {
    id: nextId("fx"),
    typeId: "delay",
    bypassed: false,
    params: { time: 0.3, feedback: 0.4, mix: 0.5 },
    ...overrides,
  };
}

export function makeModRoute(overrides: Partial<ModRoute> = {}): ModRoute {
  return {
    id: nextId("mod"),
    source: "lfo1",
    destination: "filterCutoff",
    amount: 0.5,
    bipolar: true,
    ...overrides,
  };
}

