    mixer.getOrCreateStrip("t1");
    mixer.removeStrip("t1");
    expect(mixer.getStrip("t1")).toBeUndefined();
  });

  it("getAllStrips returns all active strips", () => {
    mixer.getOrCreateStrip("t1");
