    id: "clip-1",
    trackId: "t1",
    sourceId: "src-wav-1",
    startTime: 0,
    duration: 4,
    gain: 0.8,
    fadeIn: 0.1,
    fadeOut: 0.2,
  });

  const midiClip = makeMidiClip({
    id: "clip-2",
    trackId: "t2",
    startTime: 0,
    duration: 8,
    noteEvents: [
      makeNoteEvent({ id: "n1", pitch: 60, velocity: 100, startTime: 0, duration: 0.5 }),
      makeNoteEvent({ id: "n2", pitch: 64, velocity: 80, startTime: 0.5, duration: 0.5 }),
      makeNoteEvent({ id: "n3", pitch: 67, velocity: 90, startTime: 1.0, duration: 1.0 }),
    ],
  });

  return {
    version: SESSION_VERSION,
    meta: { name: "Test Session", createdAt: now, updatedAt: now },
    transport: { bpm: 140, loopEnabled: true, loopStart: 0, loopEnd: 8 },
    tracks: [
      { ...track1, clipIds: ["clip-1"] },
      { ...track2, clipIds: ["clip-2"] },
    ],
    clips: [audioClip, midiClip],
    mixer: { masterVolume: 0.75 },
    effects: [
      {
        trackId: "t2",
        slots: [
          makeEffectSlot({ id: "fx-1", typeId: "reverb", params: { decay: 2.5, mix: 0.3 } }),
          makeEffectSlot({ id: "fx-2", typeId: "delay", params: { time: 0.375, feedback: 0.5, mix: 0.4 } }),
        ],
      },
