      clips: {},
    });

    const gen = engine.bounce(options);
    let result: IteratorResult<BounceProgress, unknown>;
    do {
      result = await gen.next();
    } while (!result.done);

    const bounceResult = result.value as { duration: number };
    expect(bounceResult.duration).toBe(0);
  });

  it("rejects invalid sample rate", async () => {
